// ErrorCode represents an HVAC error code with diagnostic information.
type ErrorCode struct {
	ID                string   `json:"id"`                 // Unique identifier (e.g., "LG-E1")
	Brand             string   `json:"brand"`               // LG, Samsung, Springer, Daikin, etc.
	Code              string   `json:"code"`               // Display code (e.g., "E1", "CH01")
	Name              string   `json:"name"`                // Short name (e.g., "Indoor Fan Motor Error")
	Subsystem         string   `json:"subsystem"`           // indoor_unit, outdoor_unit, compressor, etc.
	Severity          string   `json:"severity"`            // critical, warning, info
	Description      string   `json:"description"`          // What the error means
	RootCauses        []string `json:"root_causes"`         // Possible causes
	DiagnosticSteps   []string `json:"diagnostic_steps"`    // How to diagnose
	TestPoints        []string `json:"test_points"`         // What to measure
	ResetProcedure    []string `json:"reset_procedure"`      // How to reset
	PartsLikelyNeeded []string `json:"parts_likely_needed"` // Common replacement parts
	RelatedCodes      []string `json:"related_codes"`       // Often accompany or confused with
}

