// AllErrorCodes returns all error codes flattened
func AllErrorCodes() []ErrorCode {
	var all []ErrorCode
	for _, codes := range BrandErrorCodes {
		all = append(all, codes...)
	}
	return all
}

// GetErrorCodeByBrand returns error codes for a specific brand
func GetErrorCodeByBrand(brand string) []ErrorCode {
	brandLower := strings.ToLower(brand)
	var result []ErrorCode
	for b, codes := range BrandErrorCodes {
		if strings.ToLower(b) == brandLower || strings.Contains(strings.ToLower(b), brandLower) {
			result = append(result, codes...)
		}
	}
	return result
}

// GetErrorCode returns a specific error code by brand and code
func GetErrorCode(brand, code string) *ErrorCode {
	brandLower := strings.ToLower(brand)
	codeUpper := strings.ToUpper(code)
	for b, codes := range BrandErrorCodes {
		if strings.ToLower(b) == brandLower || strings.Contains(strings.ToLower(b), brandLower) {
			for _, ec := range codes {
				if strings.ToUpper(ec.Code) == codeUpper {
					return &ec
				}
			}
		}
	}
	return nil
}

// SearchErrorCodes searches error codes by keyword in name, description, or root cause
func SearchErrorCodes(keyword string) []ErrorCode {
	keywordLower := strings.ToLower(keyword)
	var result []ErrorCode
	for _, codes := range BrandErrorCodes {
		for _, ec := range codes {
			if strings.Contains(strings.ToLower(ec.Name), keywordLower) ||
				strings.Contains(strings.ToLower(ec.Description), keywordLower) ||
				strings.Contains(strings.ToLower(ec.Code), keywordLower) {
				result = append(result, ec)
			}
		}
	}
	return result
}
